I have been thinking of feature detecting first and then construct the saveAs method with what is avalible instead of trying everything in the same flow

> creating conditional function depending in javascript


```js
// instead of doing
 saveAs = function(...args) {

  if (supportsSaveAndOpen()) {
    use_IE_solution(args);
  } else if ( supportsAdownload() ) {
    use_a_download();
  } else {
    use_file_reader(args)
  }
}

// You can do
if (supportsSaveAndOpen() ) {
  saveAs = use_IE_solution
} else if (supportsAdownload() ) {
  saveAs = use_a_download
} else if (supportsFileReader()){
  saveAs = use_file_reader
} else {
  saveAs = () => { "can't save :(" }
}
```

That way you can garbage collect the other bloated code and the function will be more clean

